export const handler = async (input) => {
  console.log("Input received:", input);

  // 🛑 NEW: Early return if credit score is -1
  if (input.customer.credit_score === -1) {
    const recommended_aa_limit = 25000;
    console.log("Credit score is -1, returning fixed limit:", recommended_aa_limit);
    return { recommended_aa_limit };
  }

  const occupation = input.customer?.occupation || 0;
  const min_months_salary = input.customer?.min_months_salary || 0;
  const avg_credits = input.customer?.avg_credits || 0;

  console.log("Eligible account types:", {
    occupation,
    min_months_salary,
    avg_credits
  });

  const aa_policy = input.aa_policy;
  console.log("AA policy:", aa_policy);

  let aa_limit;
  let recommended_aa_limit;

  if (occupation === "SALARIED") {
    aa_limit = min_months_salary;
  } else if (occupation === "SELF-EMPLOYED") {
    aa_limit = 0.8 * avg_credits;
  } else {
    console.log("Occupation type not recognized, rejecting.");
    return { aa_limit: 0 };
  }

  console.log("Limit:", aa_limit);

  // Round down aa_limit to the nearest thousand
  recommended_aa_limit = Math.floor(aa_limit / 1000) * 1000;

  console.log("Maximum limit calculated:", recommended_aa_limit);

  return { recommended_aa_limit };
};

